14	export function ProbabilityBar({ outcomes, marginals }: ProbabilityBarProps) {
15	  return (
16	    <div>
17	      <div
18	        style={{
19	          display: "flex",
20	          height: 24,
21	          borderRadius: "var(--radius-sm)",
22	          overflow: "hidden",
23	          background: "var(--color-bg)",
24	        }}
25	      >
26	        {outcomes.map((o, i) => {
27	          const p = marginals[o.id] ?? 0;
